    @staticmethod
    def _significance_stars(p_value: float) -> str:
        """Convert p-value to significance stars."""
        if p_value < 0.01:
            return "***"
        elif p_value < 0.05:
            return "**"
        elif p_value < 0.10:
            return "*"
        else:
            return ""
